"""MCP server commands for GreenNode AgentBase CLI."""

import logging
import sys

import click
from rich.console import Console

from . import CONTEXT_SETTINGS
from ..core.logging import configure_logger

logger = logging.getLogger("greennode_agentbase.cli.mcp")
configure_logger(logger)
console = Console()


def _check_mcp_deps() -> bool:
    """Return True if MCP optional deps (fastmcp, trafilatura) are available."""
    try:
        import fastmcp  # noqa: F401
        import trafilatura  # noqa: F401
        return True
    except ImportError:
        return False


def _mcp_coming_soon() -> None:
    """Print 'MCP CLI is coming soon' and exit. Used when MCP CLI is not yet available."""
    console.print("[yellow]MCP CLI is coming soon.[/yellow]")
    raise SystemExit(0)


@click.group(name="mcp", context_settings=CONTEXT_SETTINGS, invoke_without_command=True)
@click.pass_context
def mcp_group(ctx: click.Context) -> None:
    """Run the GreenNode AgentBase helper MCP server (list_available_guides, read_guide_page)."""
    if ctx.invoked_subcommand is None:
        _mcp_coming_soon()


def _run_serve() -> None:
    """Start the MCP server. Requires Python 3.10+ and: pip install greennode-agentbase[mcp]."""
    if sys.version_info < (3, 10):
        console.print("[red]Error: MCP server requires Python 3.10 or newer.[/red]")
        raise SystemExit(1)
    if not _check_mcp_deps():
        console.print(
            "[red]Error: MCP optional dependencies are not installed.[/red]\n"
            "Install them with: [bold]pip install greennode-agentbase[mcp][/bold]"
        )
        raise SystemExit(1)
    from ..mcp.server import get_app

    get_app().run()


@mcp_group.command(name="serve")
def serve() -> None:
    """Start the MCP server. Requires Python 3.10+ and: pip install greennode-agentbase[mcp]."""
    _mcp_coming_soon()


@mcp_group.command(name="run")
def run_cmd() -> None:
    """Alias for 'serve': start the MCP server."""
    _mcp_coming_soon()
